{
  "core_question": "How should the board evaluate the clinical, legal, and financial implications of converting a 90‑bed rural nonprofit hospital to a for‑profit entity, spinning out a charitable foundation, and executing a sale‑leaseback of the real estate?",
  "rationale": "The transaction spans clinical operations, nonprofit status and regulatory compliance, and complex financial structuring, requiring expertise from healthcare, legal, and finance specialists.",
  "routes": ["healthcare", "legal", "finance"],
  "sub_questions": {
    "healthcare": "What clinical and quality‑of‑care considerations must the board evaluate when converting a 90‑bed rural nonprofit hospital to a for‑profit entity, including impacts on patient outcomes, staffing, and community benefit obligations under CMS regulations?",
    "legal": "What legal and regulatory issues must the board address in structuring the sale‑leaseback of the hospital real estate and the spin‑out of a charitable foundation holding the proceeds, including nonprofit status preservation, fiduciary duties, and compliance with state and federal laws?",
    "finance": "What financial analysis should the board conduct to evaluate the feasibility and value of the sale‑leaseback transaction, including valuation of the hospital, lease terms, tax implications, and projected cash flows for the for‑profit entity and the charitable foundation?"
  },
  "requires_recency_disclosure": true,
  "recency_notes": "Recent IRS guidance on sale‑leaseback for nonprofit hospitals, changes to tax treatment of charitable foundations, and updated Medicare reimbursement rules for rural hospitals."
}

