  "sub_questions": {
    "healthcare": "What are the key clinical considerations—including patient care quality metrics, workforce retention, Medicare/Medicaid eligibility, and potential impacts on community health outcomes—that the board should evaluate when a nonprofit hospital converts to a for‑profit entity under this acquisition structure?",
    "legal": "What legal issues must the board address regarding (1) the conversion of the operating entity from nonprofit to for‑profit while maintaining charitable foundation ownership of proceeds, (2) the sale‑leaseback arrangement of hospital real estate, and (3) compliance with IRS 501(c)(3) rules, state hospital licensing, and fiduciary duties under this transaction?",
    "finance": "What financial analyses should the board perform to assess the viability of the acquisition, including valuation of the hospital assets, lease terms for the sale‑leaseback, projected cash flows, tax implications for both the new for‑profit entity and the charitable foundation, and expected returns to the private‑equity sponsor?"
  },
  "requires_recency_disclosure": true,
  "recency_notes": "IRS 501(c)(3) sale‑leaseback guidance, CMS regulations on nonprofit hospitals, recent state licensing changes, and current market rates for hospital real estate leases."
}

